/// <summary>
/// Core training for the lead-scoring admin surfaces: Lead Sources catalog
/// (/admin/lead-sources), ICP Rubrics + weighted dimensions (/admin/icp-rubrics),
/// and Entity Completeness requirement rows (/admin/entity-completeness).
///
/// Fills the major-gap "taught: no" coverage identified in the training audit:
/// the catalog CRUD, the immutable Code + nightly Quality Score, the
/// single-default rubric invariant, weighted-dimension scoring (rubric →
/// Lead.IcpScore → work-queue ordering), MatchSpec / predicate JSON authoring,
/// and the i18n-key wiring on completeness rows.
/// </summary>
public class LeadScoringTraining : TrainingContentBase
{
    public LeadScoringTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Lead Sources & Quality Scores (Article) ──────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Sources & Quality Scores",
            Slug = "lead-sources-overview",
            Summary = "Manage the Lead Sources catalog: a Name plus an immutable Code, the nightly auto-computed Quality Score, and why you deactivate a source instead of deleting it once leads are attributed to it.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/admin/lead-sources"]""",
            Tags = """["lead-scoring","lead-sources","admin","leads"]""",
            ContentJson = """{"body":"## Lead Sources & Quality Scores\n\nThe **Lead Sources** catalog (Admin → Lead Sources) is the authoritative list of where your leads come from — trade shows, a purchased list, the website contact form, a referral partner, a specific ad campaign. Every lead can be attributed to a source, and bulk-intake stamps that attribution automatically. Cataloging your sources lets you measure which channels actually produce business and which deliver garbage.\n\n### Name vs Code — and why Code is immutable\n\nA lead source has two identifiers:\n\n- **Name** — the human-readable label (e.g., 'IMTS 2026 Trade Show', 'Website Contact Form'). Fully editable; rename it whenever you like.\n- **Code** — a short, stable identifier (e.g., `imts-2026`, `web-contact`). The Code is set once when you create the source and **can never be changed afterward**. In the edit dialog the Code field is disabled.\n\nThe Code is the natural key that the rest of the system binds to: bulk-import pipelines map a column to a source Code, web forms and referrer URLs carry the Code, and historical leads point at it. If the Code could change, every one of those bindings would silently break. So choose it carefully at create time. The Code accepts letters, digits, hyphens, and underscores only.\n\n### The Quality Score\n\nEvery source carries a **Quality Score** from 0 to 100. This is **not** something you type in — it is computed automatically by a nightly background job from the *outcomes* of that source's leads. You cannot edit it; the column is read-only on this screen.\n\nThe score is a rolling measure of how good a source's leads turn out to be:\n\n- Every source starts at a neutral **50**.\n- Leads that **convert** to customers pull the score **up** (the strongest positive signal).\n- Leads that **engage** (a real two-way conversation) pull it **up** modestly.\n- Leads marked **Bad Data** or **Suppressed** (do-not-contact) pull it **down**.\n- Leads marked **Lost** pull it **down** modestly.\n- Only leads from roughly the **last 180 days** count — that window is what makes the score *rolling*, so a source that improved (or degraded) recently is reflected, not its all-time history.\n\nThe final number is clamped to 0–100. In the table the score is color-coded: green at 70+ (a strong source), amber from 40–69 (mixed), red below 40 (this channel is delivering leads that don't pan out — investigate the list provider or campaign).\n\nBecause the job runs nightly, the score lags real-time. A brand-new source sits at 50 until its leads accumulate outcomes and the next run picks them up.\n\n### Creating and editing a source\n\nClick **New Source** in the toolbar. Provide a **Name** and a **Code** (both required), and optionally a **Description** explaining what the source is. Save. When you edit an existing source you can change the Name, Description, and the **Active** toggle — but not the Code.\n\n### Deactivate vs Delete\n\nThere are two ways to retire a source, and they are not interchangeable:\n\n- **Deactivate** (set the Active toggle off) — the source stays in the system and stays attached to all its historical leads, but it no longer appears as a choice for new intake. Use this whenever a source has *any* leads attributed to it. Historical attribution survives, so your reporting and the source's Quality Score stay intact.\n- **Delete** (the trash icon) — permanently removes the source. The server **blocks the delete** with an error if any leads are linked to it. This is a guard rail: you can only hard-delete a source that was created by mistake and never used. If leads exist, the system tells you to deactivate instead.\n\nThe practical rule: **if a source has ever been used, deactivate it; only delete the truly-empty mistakes.**\n\n### How this feeds the rest of the system\n\nThe source on a lead is one of the fields the ICP scoring job can match against (see *ICP Rubrics & Weighted Dimensions*), and the per-source Quality Score helps you decide where to spend your lead-generation budget. Sources, rubrics, and completeness rules together make up the lead-scoring admin area.","sections":[]}"""
        });

        // ── ICP Rubrics & Weighted Dimensions (Article) ──────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "ICP Rubrics & Weighted Dimensions",
            Slug = "icp-rubrics-overview",
            Summary = "Build an Ideal Customer Profile rubric out of weighted dimensions, understand the single-default invariant, and follow the end-to-end path: rubric → nightly Lead.IcpScore → work-queue ordering.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","icp","rubrics","admin","leads"]""",
            ContentJson = """{"body":"## ICP Rubrics & Weighted Dimensions\n\nAn **ICP rubric** (Ideal Customer Profile) is a scoring sheet that grades how well a lead fits the kind of customer you actually want. Admin → ICP Rubrics is where you build and tune those rubrics. The output is a 0–100 **fit score** stamped on every active lead, which the rep work-queue uses to surface the best-fit leads first.\n\n### The end-to-end picture (read this first)\n\nIt's worth understanding the whole chain before touching the editor:\n\n1. You define a **rubric** made of weighted **dimensions** (industry, company size, location, etc.).\n2. One rubric is flagged **Default** (and **Active**).\n3. A **nightly job** checks the default rubric's dimensions against every active lead, adds up the weights of the ones that match, scales the total to 0–100, and saves it as the lead's fit score.\n4. The **lead work-queue** orders leads by that score, so reps spend their time on the highest-fit prospects.\n\nNothing scores in real time — the score you see on a lead is the cached result of the last nightly run. Edit a rubric today, and the new weights take effect on the next run.\n\n### Rubric header fields\n\nClick **New Rubric** (or a row to edit). A rubric has:\n\n- **Name** (required) — e.g., 'Aerospace Machining ICP'.\n- **Description** — free-text reminder of who this rubric targets.\n- **Active** — whether the rubric is in play at all.\n- **Default** — whether this is *the* rubric the nightly scoring job uses.\n\n### The single-default invariant\n\nThe scoring job uses exactly one rubric: the one that is both **Active** and **Default**. The server enforces that **at most one rubric is the default** — when you mark a rubric as Default, the previously-default rubric is automatically un-defaulted in the same save. You never have to hunt down the old default and turn it off; flipping the flag on a new rubric is enough.\n\nA consequence worth internalizing: if **no** rubric is Active+Default, or the default rubric has **no dimensions**, or all its dimensions have **zero/negative** weight, the nightly job logs that it skipped and **no scores are written**. A rubric with dimensions but no positive weight can't produce a meaningful 0–100 score.\n\n### Dimensions — the weighted scoring rows\n\nInside the rubric editor is a **Dimensions** section. Each dimension is one criterion the lead is graded on. Add as many as you need with **Add Dimension**; each row has four fields:\n\n- **Field Key** (required) — the lead/account attribute this dimension looks at. Common keys: `industry`, `employeeCount`, `state`, `companyName`, `source`. (This is a documentation/intent field that pairs with the Match Spec — see the Match Spec walkthrough for exactly how a lead is matched.)\n- **Label** — a human description so you remember what the row targets ('Target aerospace & defense').\n- **Match Spec** — a small JSON snippet describing what counts as a *hit*. Covered in depth in *Authoring ICP Match Specs*.\n- **Weight** (required) — the points this dimension contributes when it matches. **Positive** weights reward a fit; **negative** weights penalize an anti-fit (e.g., −10 for an industry you don't serve).\n\n### How the score is computed\n\nFor each lead, the job walks every dimension, and for the ones whose Match Spec matches the lead, it adds that dimension's weight. The running total is divided by the **sum of all positive weights** (the maximum achievable), multiplied by 100, and clamped to 0–100. So:\n\n- A lead that hits your highest-weighted dimensions lands near 100.\n- A lead that hits nothing (or trips negative-weight penalties) lands near 0.\n- The *relative* weights are what matter — doubling every weight changes nothing, because the denominator scales with it.\n\n### Saving\n\nThe editor saves the header and the dimensions together in one action. Deleting a dimension row and saving removes it. Because several dimensions are usually tuned at once, the save is one round-trip and produces one rolled-up activity entry rather than one per row.\n\n### Where to go next\n\nThe Match Spec column is the one part of a dimension that has real syntax. *Authoring ICP Match Specs* walks through the exact JSON shapes the scoring job understands.","sections":[]}"""
        });

        // ── Authoring ICP Match Specs (Walkthrough) ──────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Authoring ICP Match Specs",
            Slug = "icp-match-specs-walkthrough",
            Summary = "A guided tour of the ICP Rubrics page that explains how to author the Match Spec JSON on each dimension — string lists, industry/state objects, and numeric size ranges — and how the nightly job evaluates them.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","icp","match-spec","walkthrough","admin"]""",
            ContentJson = """{"appRoute":"/admin/icp-rubrics","startButtonLabel":"Tour ICP Rubrics","steps":[{"element":".toolbar__hint","popover":{"title":"ICP Rubrics","description":"This page lists every ideal-customer-profile rubric. Each night, the scoring job takes the one rubric that is both Active and Default and grades every active lead from 0 to 100. That score is what puts the best-fit leads at the top of a rep's work list.","side":"bottom"}},{"element":"[data-testid='icp-rubric-new-btn']","popover":{"title":"New Rubric","description":"Click here to create a rubric, or click a row to edit one. The editor holds the rubric's basics (Name, Description, Active, Default) and its scoring rows together, and saves them all at once.","side":"left"}},{"element":"app-data-table","popover":{"title":"The rubric list","description":"Each row shows the rubric's name, how many scoring rows it has, and labels for Default and Active. Only one rubric can be the Default — pick a new one and the old one is unmarked for you. The row count tells you at a glance whether a rubric can actually score anything.","side":"top"}},{"element":"app-data-table","popover":{"title":"Dimensions and the Match Spec","description":"Open a rubric to see its scoring rows. Each row has a field key, a label, a weight, and a Match Spec. The Match Spec is the one field with real syntax: a small piece of JSON that tells the nightly job what counts as a match for that row. The next steps walk through the three shapes it understands.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match Spec shape 1 — a string list","description":"Open a rubric to try this. A list of words, like [\"aerospace\",\"defense\",\"machining\"], is a case-insensitive partial-text match. The job looks for each word in the lead's company name, source, and email, and — if the lead is tied to an account — the account's industry, state, size, and name. Find any word anywhere, and the row matches and adds its weight.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match Spec shape 2 — keyed objects","description":"Open a rubric to try this. An object targets one account field exactly. { \"industries\": [\"Aerospace\",\"Defense\"] } matches the account's industry exactly (ignoring case). { \"states\": [\"CA\",\"WA\",\"TX\"] } matches the account's state. Use these when you want a precise field match instead of a loose text search.","side":"top"}},{"element":"app-data-table","popover":{"title":"Match Spec shape 3 — a numeric range","description":"Open a rubric to try this. { \"min\": 50, \"max\": 500 } matches when the account's size falls between min and max — for example, companies with 50 to 500 employees. Anything the job can't read (broken JSON, an unfamiliar shape, or a blank box) simply counts as no match, and you can see and fix it in the editor.","side":"top"}},{"element":"[data-testid='icp-rubric-save-btn']","popover":{"title":"Tune, save, wait for the run","description":"Give positive weights to the rows you want to reward and negative weights to the ones you want to penalize. Save the rubric. The change takes effect on the next nightly run, which re-scores every active lead and re-orders the work list.","side":"left"}}]}"""
        });

        // ── Entity Completeness Requirements Admin (Article) ──────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Entity Completeness Requirements",
            Slug = "entity-completeness-overview",
            Summary = "Author capability-indexed completeness rules for Vendor, Part, and Customer records: what a requirement row is, the predicate JSON DSL, the i18n display/message keys, and how the completeness chip consumes them.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/entity-completeness"]""",
            Tags = """["lead-scoring","entity-completeness","predicates","admin"]""",
            ContentJson = """{"body":"## Entity Completeness Requirements\n\nAdmin → Entity Completeness lets you define what it means for a record to be **complete enough to be used**. Each row answers one question: *\"for an entity of type X to participate in the workflows that capability Y unlocks, what must be true about that record?\"* The completeness chip on Vendor, Part, and Customer detail screens reads these rows and lists exactly what's still missing.\n\nThis catalog ships **empty** by design — the requirements an install needs depend on which capabilities it has turned on, so you author the rows yourself rather than fighting a pre-seeded set that doesn't fit.\n\n### What one requirement row contains\n\nClick **New Requirement** to open the dialog. A row has these fields:\n\n- **Entity Type** (required) — which record this applies to: **Vendor**, **Part**, or **Customer**.\n- **Capability Code** (required) — a capability from the catalog, e.g. `CAP-MD-VENDORS`, `CAP-P2P-PO`. The requirement only matters in the context of that capability.\n- **Requirement Id** (required) — a short stable id for *this specific requirement* within the (Entity Type, Capability) pair, e.g. `tax-id`, `payment-terms`, `billing-address`. This is what lets one capability declare several discrete requirements that each show up individually in the missing-fields list.\n- **Predicate** (required) — the JSON rule that must evaluate **true** for the record to satisfy this requirement (the syntax is below).\n- **Display Name Key** (required) — an **i18n key** for the short label shown in the chip popover (e.g. `entityCompleteness.fields.taxId` → 'Tax ID').\n- **Missing Message Key** (required) — an **i18n key** for the fuller explanation shown when the requirement isn't met (e.g. 'Vendor needs a federal tax ID before being added to a purchase order').\n- **Sort Order** — display order within the (Entity Type, Capability) grouping.\n\nBecause Entity Type + Capability Code + Requirement Id are **unique together**, you add multiple rows — one per discrete requirement — rather than cramming several checks into one predicate, so each shows up as its own line item in the chip.\n\n### The predicate DSL\n\nThe Predicate is JSON evaluated by the shared predicate engine (the same one the guided-workflow readiness gates use). Every predicate is an object with a `type`. Field names are written in **camelCase** and are matched against the loaded entity's properties. The available operators:\n\n- **`fieldPresent`** — the value is not null, and for strings, not empty. `{ \"type\": \"fieldPresent\", \"field\": \"taxId\" }`\n- **`fieldEquals`** — strict equality. `{ \"type\": \"fieldEquals\", \"field\": \"creditTerms\", \"value\": \"Net30\" }`\n- **`fieldCompare`** — numeric comparison with an op of `gt` / `lt` / `gte` / `lte` / `ne`. `{ \"type\": \"fieldCompare\", \"field\": \"leadTimeDays\", \"op\": \"gt\", \"value\": 0 }`\n- **`relationExists`** — a child collection has at least `minCount` items. `{ \"type\": \"relationExists\", \"relation\": \"addresses\", \"minCount\": 1 }`\n- **`relationCountCompare`** — the collection size compared by op + value.\n- **`all`** / **`any`** / **`not`** — boolean composition over nested predicates. `all` and `any` take an `of` array; `not` takes one nested predicate under `of`.\n\nA composite example — a vendor must have a tax id AND at least one address:\n\n```\n{ \"type\": \"all\", \"of\": [\n  { \"type\": \"fieldPresent\", \"field\": \"taxId\" },\n  { \"type\": \"relationExists\", \"relation\": \"addresses\", \"minCount\": 1 }\n] }\n```\n\nImportant safety behavior: an **unknown field, unknown operator, or malformed JSON short-circuits to `false`** (the requirement is treated as *not met*) and logs a single warning. The record will simply look incomplete until you fix the predicate — it never crashes the chip.\n\n### Wiring the i18n keys\n\nThe Display Name Key and Missing Message Key are *keys*, not literal text. For the chip to show real words instead of a raw token, the matching translation entries must exist in the language files (`en.json`, and `es.json` for parity). If a key has no translation, the UI falls back to the raw key string — that's your signal that the wiring is incomplete. Pick a consistent key prefix (the existing convention is `entityCompleteness.fields.*` for labels and `entityCompleteness.messages.*` for explanations) so the keys stay organized.\n\n### How the chip uses all this\n\nWhen a user opens a Vendor / Part / Customer, the completeness evaluator pulls every requirement row for that entity type whose capability is enabled, loads the record, and runs each predicate. Requirements that evaluate **false** become the chip's missing-fields list — each rendered with its Display Name (and the fuller Missing Message in the popover), ordered by Sort Order. Requirements that pass are silent. This is also the foundation for future hard blocks (e.g., refusing to add a vendor to a PO until its PO-required fields are present).\n\n### Filtering and editing\n\nThe page toolbar filters the list by Entity Type and by Capability Code so you can manage a large ruleset. Edit a row with the pencil icon; delete with the trash icon (with a confirm). Editing a predicate takes effect immediately on the next completeness evaluation — there is no nightly job here.","sections":[]}"""
        });

        // ── Authoring a Completeness Requirement (Walkthrough) ────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Authoring a Completeness Requirement",
            Slug = "entity-completeness-walkthrough",
            Summary = "A guided tour of the Entity Completeness admin page: filtering the ruleset, opening the New Requirement dialog, and authoring the entity type, capability code, requirement id, predicate JSON, and i18n keys.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/admin/entity-completeness"]""",
            Tags = """["lead-scoring","entity-completeness","walkthrough","admin"]""",
            ContentJson = """{"appRoute":"/admin/entity-completeness","startButtonLabel":"Tour Entity Completeness","steps":[{"element":"app-toolbar","popover":{"title":"Entity Completeness admin","description":"This page is where you write the completeness rules for vendor, part, and customer records. The list starts empty — you add the rows your turned-on features need. The completeness label on each record reads these rows and shows what's still missing.","side":"bottom"}},{"element":"app-select","popover":{"title":"Filter by entity type","description":"Pick from this menu to narrow the list to vendor, part, or customer rows (or all of them). As your rule set grows, this is how you find the rows for the record type you're working on.","side":"bottom"}},{"element":"app-input","popover":{"title":"Filter by capability","description":"Type a capability code to see only the requirements tied to that feature. Each requirement belongs to one feature — it only applies when that feature is turned on.","side":"bottom"}},{"element":"[data-testid='ecr-new-btn']","popover":{"title":"New Requirement","description":"Open the form to add a requirement. You'll pick the entity type, the feature it belongs to, a short stable id, the rule itself, two translation labels, and a sort order.","side":"left"}},{"element":"app-data-table","popover":{"title":"The requirement rows","description":"Each row is one check. Entity type, feature, and requirement id are unique as a set, so you add several rows — one per check — and each shows up on its own line in the missing list. The two label columns are translation keys, not the words a user sees.","side":"top"}},{"element":"app-data-table","popover":{"title":"The predicate","description":"The rule is written as JSON the shared rule engine understands: check a field is filled in (fieldPresent), equal to a value (fieldEquals), or compared as a number (fieldCompare); check a related list has entries (relationExists); and combine checks with all/any/not. Field names are camelCase. A broken or unfamiliar rule safely counts as unmet (the record just looks incomplete) — it never breaks the label.","side":"top"}},{"element":"[data-testid='ecr-new-btn']","popover":{"title":"Don't forget the translations","description":"The two label fields point at entries in the language files (English plus Spanish, kept in sync). If a label has no translation, you'll see the raw key on screen — that's your cue the translation is missing. Keep the naming consistent with the existing labels and messages so everything stays organized.","side":"left"}}]}"""
        });

        // ── Lead Scoring Admin Field Reference (QuickRef) ─────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Scoring Admin Field Reference",
            Slug = "lead-scoring-field-reference",
            Summary = "Quick reference for the three lead-scoring admin surfaces: Lead Source fields and Quality-Score math, ICP rubric/dimension fields and Match Spec shapes, and Entity Completeness fields with the full predicate DSL.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 6,
            AppRoutes = """["/admin/lead-sources","/admin/icp-rubrics","/admin/entity-completeness"]""",
            Tags = """["lead-scoring","reference","admin"]""",
            ContentJson = """{"title":"Lead Scoring Admin Field Reference","groups":[{"heading":"Lead Sources — Fields","items":[{"label":"Name","value":"Required. The label people read. Editable any time."},{"label":"Code","value":"Required, set when you create the source, and can't be changed afterward (it's locked when you edit). It's the stable id that imports, forms, and referral links point to. Letters, digits, hyphens, and underscores only."},{"label":"Description","value":"Optional note describing the source (up to 500 characters)."},{"label":"Quality Score","value":"0–100, read-only. Worked out automatically each night from how the source's leads turn out — you never type it. Colored green at 70+, amber 40–69, red under 40."},{"label":"Active","value":"On/off switch (edit only). Off = hidden from new intake but still tied to its past leads."},{"label":"Leads","value":"How many leads are tied to this source. This is what the delete guard checks."},{"label":"Created","value":"The date it was created, shown as MM/dd/yyyy."}]},{"heading":"Lead Sources — Quality Score math","items":[{"label":"Starting value","value":"Every source starts at 50 (neutral)."},{"label":"+5 each","value":"A lead that turned into a customer (the strongest plus)."},{"label":"+2 each","value":"A lead that had a real back-and-forth conversation."},{"label":"−5 each","value":"A lead marked bad data or do-not-contact."},{"label":"−2 each","value":"A lead marked lost."},{"label":"Window","value":"Only leads from about the last 180 days count — that's what keeps the score current."},{"label":"Clamp","value":"The final score is kept within 0–100, and the time of each nightly run is recorded."}]},{"heading":"Lead Sources — Deactivate vs Delete","items":[{"label":"Deactivate","value":"Turn Active off. Use this whenever the source has any leads. Keeps its history and its score."},{"label":"Delete","value":"Trash icon. Blocked with an error if any leads are tied to it. Only for sources created by mistake and never used."}]},{"heading":"ICP Rubric — Header fields","items":[{"label":"Name","value":"Required. Names the rubric (up to 100 characters)."},{"label":"Description","value":"Optional reminder of who the rubric is aimed at (up to 500)."},{"label":"Active","value":"Whether the rubric is in play."},{"label":"Default","value":"Whether this is the rubric the nightly scoring uses. Only one can be the default — pick a new one and the old one is unmarked for you."},{"label":"Dimensions count","value":"Shown in the list; tells you whether the rubric can actually score anything."}]},{"heading":"ICP Dimension — Row fields","items":[{"label":"Field Key","value":"Required. The lead or account detail this row looks at (industry, employeeCount, state, companyName, source). A note-to-self that pairs with the Match Spec."},{"label":"Label","value":"Optional plain description of what the row is looking for."},{"label":"Match Spec","value":"JSON that says what counts as a match (shapes below). Blank or broken = no match."},{"label":"Weight","value":"Required whole number. Positive rewards a fit; negative penalizes a poor fit. Only positive weights count toward the top score."}]},{"heading":"ICP Match Spec — Shapes","items":[{"label":"String array","value":"[\"aerospace\",\"defense\"] — a case-insensitive partial-text match against the lead's company name, source, and email, and the account's industry, state, size, and name. Any word found in any field is a match."},{"label":"{ industries: [...] }","value":"An exact match (ignoring case) against the linked account's industry."},{"label":"{ states: [...] }","value":"An exact match against the linked account's state."},{"label":"{ min: N, max: M }","value":"A number range from min to max against the account's size."},{"label":"Anything else","value":"An unfamiliar shape, broken JSON, or a blank box counts as no match (never an error)."}]},{"heading":"ICP — Scoring math","items":[{"label":"Per lead","value":"Add up the weight of every row whose Match Spec matches."},{"label":"Normalize","value":"Divide that total by the sum of the positive weights, multiply by 100, round, and keep it within 0–100."},{"label":"Written to","value":"Saved on the lead as its fit score by the nightly run, for leads that aren't already won or lost."},{"label":"Consumed by","value":"The rep work list, which puts the best-fit leads first."},{"label":"Skip conditions","value":"No active default rubric, the default has no rows, or no positive weight → the run is skipped and no scores are written."}]},{"heading":"Entity Completeness — Row fields","items":[{"label":"Entity Type","value":"Required. Vendor, part, or customer."},{"label":"Capability Code","value":"Required. The feature this requirement belongs to (for example, the vendor or purchase-order features)."},{"label":"Requirement Id","value":"Required. A short, stable id for this one check within an entity-type-and-feature pair. Unique as a set. For example, tax-id or payment-terms."},{"label":"Predicate","value":"Required. The rule, written as JSON, that must be true (see below)."},{"label":"Display Name Key","value":"Required. Points at the short label shown on the record. Named like entityCompleteness.fields.*"},{"label":"Missing Message Key","value":"Required. Points at the fuller 'why it's missing' text. Named like entityCompleteness.messages.*"},{"label":"Sort Order","value":"The order it shows in, within its entity-type-and-feature group."}]},{"heading":"Predicate DSL — Operators","items":[{"label":"fieldPresent","value":"{ type:'fieldPresent', field:'taxId' } — the field is filled in (and, for text, not blank)."},{"label":"fieldEquals","value":"{ type:'fieldEquals', field:'creditTerms', value:'Net30' } — the field equals an exact value."},{"label":"fieldCompare","value":"{ type:'fieldCompare', field:'leadTimeDays', op:'gt', value:0 } — a number comparison; op is gt/lt/gte/lte/ne."},{"label":"relationExists","value":"{ type:'relationExists', relation:'addresses', minCount:1 } — a related list has at least minCount entries."},{"label":"relationCountCompare","value":"Compares the size of a related list using op + value."},{"label":"all / any / not","value":"Combine checks. all and any take an 'of' list of checks; not takes one check under 'of'."},{"label":"Field casing","value":"Write field names in camelCase; the engine matches them to the record's fields."},{"label":"Safety","value":"An unknown field, unknown check, or broken JSON counts as not met and logs one warning. It never crashes."}]},{"heading":"i18n wiring","items":[{"label":"Keys not text","value":"The two label fields point at translations, not the words themselves. Matching entries must exist in both English and Spanish, kept in sync."},{"label":"Missing translation","value":"With no translation, you'll see the raw key on the record — your signal it's not wired up yet."}]},{"heading":"Routes & gating","items":[{"label":"/admin/lead-sources","value":"The Lead Sources list. Create and update: Admins and Managers. Delete: Admins."},{"label":"/admin/icp-rubrics","value":"ICP rubrics and their scoring rows. Admins and Managers (Delete: Admins)."},{"label":"/admin/entity-completeness","value":"The completeness requirement rows. Admins only."}]}]}"""
        });

        // ── Lead Scoring Admin Knowledge Check (Quiz) ─────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Scoring Admin Knowledge Check",
            Slug = "lead-scoring-quiz",
            Summary = "Test your understanding of Lead Sources, ICP rubrics and weighted dimensions, Match Spec JSON, and Entity Completeness predicates.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 7,
            AppRoutes = """["/admin/lead-sources","/admin/icp-rubrics","/admin/entity-completeness"]""",
            Tags = """["lead-scoring","quiz","admin"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ls1","text":"Why can't you change a Lead Source's Code after it's created?","options":[{"id":"a","text":"The Code is the stable natural key that imports, web forms, and referrer URLs bind to — changing it would silently break that attribution","isCorrect":true},{"id":"b","text":"The Code is encrypted and the system has no way to decrypt it"},{"id":"c","text":"Codes are reused across installs and must stay globally unique"},{"id":"d","text":"It can be changed — the field is just hidden by default"}],"explanation":"The Code is the immutable natural key. Bulk-import pipelines map columns to a source Code, and web forms / referrer URLs carry it; historical leads point at it. If it could change, every binding would break. The edit dialog disables the Code field for exactly this reason. Choose it carefully at create time."},{"id":"ls2","text":"Where does a Lead Source's Quality Score come from?","options":[{"id":"a","text":"An admin types it into the source's edit dialog"},{"id":"b","text":"It is auto-computed nightly from the disposition outcomes of that source's leads","isCorrect":true},{"id":"c","text":"It is pulled from the list provider's API"},{"id":"d","text":"It is the simple count of leads attributed to the source"}],"explanation":"Quality Score is read-only and computed by a nightly job. Every source starts at 50; converted leads add points, engaged leads add fewer, bad-data/suppressed leads subtract, and lost leads subtract a little. Only leads from roughly the last 180 days count, which makes the score 'rolling'. It is never typed by hand."},{"id":"ls3","text":"You try to delete a Lead Source that has 40 leads attributed to it. What happens, and what should you do instead?","options":[{"id":"a","text":"It deletes and the 40 leads lose their source — that's expected"},{"id":"b","text":"The server blocks the delete; you should deactivate the source instead so historical attribution survives","isCorrect":true},{"id":"c","text":"It deletes and the 40 leads are reassigned to the default source"},{"id":"d","text":"Nothing happens — sources can never be deleted"}],"explanation":"Delete is blocked with an error when leads are linked, as a guard rail. The right action is to set the Active toggle off (deactivate): the source disappears from new-intake choices but stays attached to its historical leads, preserving attribution and the Quality Score. Only never-used mistake sources can be hard-deleted."},{"id":"ls4","text":"Which rubric does the nightly ICP scoring job actually use?","options":[{"id":"a","text":"All Active rubrics, averaging the scores together"},{"id":"b","text":"The single rubric that is both Active and Default","isCorrect":true},{"id":"c","text":"The most recently edited rubric"},{"id":"d","text":"Whichever rubric has the most dimensions"}],"explanation":"The job uses exactly one rubric: the one flagged both Active and Default. The server enforces a single default — marking a new rubric default automatically un-defaults the previous one. If no rubric is Active+Default (or it has no dimensions / no positive weight), the job skips and writes no scores."},{"id":"ls5","text":"You set an ICP dimension to match a simple list of words like 'aerospace' and 'defense'. How does a lead count as a match for that dimension?","options":[{"id":"a","text":"The lead's industry field must be typed exactly as 'aerospace' or 'defense', with nothing else accepted"},{"id":"b","text":"If any of those words appears anywhere in the lead's company name, source, email, or its linked account's industry, state, size, or name (ignoring capitalization), the dimension matches","isCorrect":true},{"id":"c","text":"Every word in the list has to appear on the lead before it counts as a match"},{"id":"d","text":"A plain word list can't be used for matching — you always have to pick a single field"}],"explanation":"A simple word list is a loose, case-insensitive 'contains' search. The scoring run looks for any of those words anywhere across the lead's company name, source, email, and — when the lead is tied to an account — that account's industry, state, size, and name. Finding just one word in any one of those places is enough for the dimension to match and add its weight. If instead you need the word to match one specific field exactly, you use the more specific keyed form that names that field."},{"id":"ls6","text":"How is a lead's final 0–100 IcpScore computed from the dimensions?","options":[{"id":"a","text":"It's the count of dimensions that matched"},{"id":"b","text":"Sum the weights of matching dimensions, divide by the sum of all positive weights, multiply by 100, and clamp to 0–100","isCorrect":true},{"id":"c","text":"It's the single highest weight among matching dimensions"},{"id":"d","text":"Each dimension is scored 0–100 separately and they're averaged"}],"explanation":"The job adds the Weight of every dimension that matches, divides by the maximum achievable (the sum of positive weights), scales to 100, and clamps to 0–100. Because the denominator scales with the weights, only the RELATIVE weights matter. Negative weights can penalize an anti-fit and push a lead toward 0."},{"id":"ls7","text":"After you edit a default rubric's dimension weights, when do lead scores reflect the change?","options":[{"id":"a","text":"Immediately — scores recompute the moment you save"},{"id":"b","text":"On the next nightly scoring run, which rewrites Lead.IcpScore for active leads","isCorrect":true},{"id":"c","text":"Only when a rep opens each lead"},{"id":"d","text":"Never — existing scores are frozen once written"}],"explanation":"Scoring is not real-time. Lead.IcpScore is a cached column written by the nightly job. Editing a rubric today means the new weights take effect on the next run, which recomputes scores for every active (non-Converted, non-Lost) lead and re-orders the work-queue."},{"id":"ls8","text":"In the Entity Completeness admin, what is the Requirement Id field for?","options":[{"id":"a","text":"It's an auto-generated database primary key you can't edit"},{"id":"b","text":"A stable id for one specific requirement within an (Entity Type, Capability) pair, so a capability can declare several discrete checks that each show up individually","isCorrect":true},{"id":"c","text":"It points at the lead source the requirement came from"},{"id":"d","text":"It's the i18n key used to render the chip label"}],"explanation":"Entity Type + Capability Code + Requirement Id are unique together. The Requirement Id (e.g. 'tax-id', 'payment-terms') lets one capability declare multiple discrete requirements on the same entity type, each surfacing as its own line in the completeness chip's missing-fields list. You add several rows rather than cramming everything into one predicate."},{"id":"ls9","text":"You want a vendor record to count as complete only once it has both a tax ID and at least one address on file. In the Entity Completeness admin, how do you set that up?","options":[{"id":"a","text":"You add a completeness requirement for the tax ID and another for having an address, so each shows up as its own item a user can check off","isCorrect":true},{"id":"b","text":"You mark the tax ID and address fields as favorites on the vendor screen"},{"id":"c","text":"You raise the vendor's quality score until the missing pieces disappear on their own"},{"id":"d","text":"Completeness is fixed by the system and can't be tailored to a vendor's needs"}],"explanation":"The Entity Completeness admin is where you author what 'complete enough to use' means for a record. You add one requirement per thing that must be true — here, a tax-ID requirement and a has-an-address requirement — each tied to the vendor record type and the feature it supports. Keeping them as separate requirements means each one appears on its own line so a user can see and fix them individually, rather than lumping several checks together."},{"id":"ls10","text":"A vendor record doesn't yet satisfy one of its completeness requirements. What does the user see happen to that record?","options":[{"id":"a","text":"The record is deleted until the missing information is supplied"},{"id":"b","text":"The record is marked as incomplete and the unmet requirement shows up in its list of what's still missing","isCorrect":true},{"id":"c","text":"The user is locked out of the record and can't open it at all"},{"id":"d","text":"Nothing shows at all, so there's no way to tell the record is missing anything"}],"explanation":"An unmet requirement doesn't delete the record or hard-block the user. Instead the record is flagged as incomplete, and that requirement appears in the record's missing list — the running tally of what still needs filling in. The user can keep working with the record and simply see, at a glance, exactly which pieces are outstanding so they know what to supply next."},{"id":"ls11","text":"A user opens a customer record and sees the completeness indicator listing 'Tax ID' and 'Billing address'. What is it telling them, and what should they do?","options":[{"id":"a","text":"Those are the pieces of information still missing from the record; the user should fill them in to make the record complete","isCorrect":true},{"id":"b","text":"Those are fields the user is not allowed to view, so they should ignore them"},{"id":"c","text":"Those are recent changes another user made, so no action is needed"},{"id":"d","text":"Those are optional suggestions that never affect whether the record can be used"}],"explanation":"The completeness indicator lists exactly the required pieces of information that this record is still missing, each shown with a short, readable label and a fuller explanation when you hover. It's a to-do list for making the record usable: the user acts on it by supplying each listed item, and as they do, those entries drop off the list until the record reads as complete."},{"id":"ls12","text":"Why does the Entity Completeness catalog ship empty?","options":[{"id":"a","text":"It's a bug — it should have default rows"},{"id":"b","text":"The requirements an install needs depend on which capabilities it has enabled, so admins author the rows that fit rather than fighting a pre-seeded set","isCorrect":true},{"id":"c","text":"Completeness rules are imported automatically from the accounting provider"},{"id":"d","text":"The rows are seeded only when the first vendor is created"}],"explanation":"Per the design choice, the catalog is empty on a fresh install. Because completeness requirements are scoped to capabilities, and every install turns on a different set of capabilities, a one-size-fits-all seed would be wrong for most installs. Admins add exactly the rows their enabled capabilities require."}]}"""
        });

        // ── Lead Scoring Admin — Advanced Reference (Reference) ───────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead scoring admin — Advanced Reference",
            Slug = "lead-scoring-reference",
            Summary = "Edge-case reference for the lead-scoring admin area: the full predicate-type syntax, the ICP MatchSpec JSON cookbook, the two nightly scoring jobs, the role/capability gating matrix, and seed-vs-admin completeness rows with i18n keys.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/admin/icp-rubrics"]""",
            Tags = """["lead-scoring","reference","advanced"]""",
            ContentJson = """{"body":"## Predicate-type reference\n\nThe Entity Completeness Predicate is JSON read by the shared `PredicateEvaluator` — the same interpreter the workflow-readiness gates use. Key predicate-DSL keys to remember (these reinforce the canonical syntax from the introductory modules), so author against the exact property names below.\n\n- **`fieldPresent`** — `{ \"type\": \"fieldPresent\", \"field\": \"taxId\" }`. True when the value is non-null (and, for strings, non-blank).\n- **`fieldEquals`** — `{ \"type\": \"fieldEquals\", \"field\": \"creditTerms\", \"value\": \"Net30\" }`. Strict equality. Strings compare ordinal/case-sensitive; numbers compare numerically; booleans match JSON `true`/`false`.\n- **`fieldCompare`** — `{ \"type\": \"fieldCompare\", \"field\": \"leadTimeDays\", \"op\": \"gt\", \"value\": 0 }`. `op` is `eq` / `ne` / `gt` / `lt` / `gte` / `lte`. `eq` and `ne` work on any value; `gt`/`lt`/`gte`/`lte` need both sides to coerce to a number (numeric-strings parse).\n- **`relationExists`** — `{ \"type\": \"relationExists\", \"relation\": \"addresses\", \"minCount\": 1 }`. The key is **`relation`, not `field`**, and the count uses **`minCount`** (default 1). A missing/unloaded collection counts as 0, so it reads as not-met.\n- **`relationCountCompare`** — `{ \"type\": \"relationCountCompare\", \"relation\": \"contacts\", \"op\": \"gte\", \"value\": 2 }`. Collection size compared by `op` + integer `value`.\n- **`all`** / **`any`** — the nested predicates live under **`of`** (an array), **not** `predicates`. `all` is logical AND, `any` is OR.\n- **`not`** — `{ \"type\": \"not\", \"of\": { ... } }`. The single nested predicate is under **`of`**.\n- **`custom`** — `{ \"type\": \"custom\", \"ref\": \"someKey\" }`. Looks the key up in the custom-function registry. The v1 registry is empty, so every `custom` predicate evaluates **false** and logs a warning until a function is registered.\n\nComposite — vendor must have a tax id AND at least one address:\n\n```\n{ \"type\": \"all\", \"of\": [\n  { \"type\": \"fieldPresent\", \"field\": \"taxId\" },\n  { \"type\": \"relationExists\", \"relation\": \"addresses\", \"minCount\": 1 }\n] }\n```\n\n**Field casing.** Write `field`/`relation` names in camelCase; the evaluator title-cases the first character and reflects against the C# entity (`taxId` → `TaxId`, `bomLines` → `BomLines`). An unknown field, unknown operator type, or malformed JSON short-circuits to **false** and logs one warning — the record simply looks incomplete; the chip never crashes and a bad predicate never silently passes.\n\n## ICP MatchSpec JSON cookbook\n\nA dimension's MatchSpec is parsed fresh each nightly run. Three shapes are understood; anything else (including blank or malformed) is a non-match.\n\n- **String array** — `[\"aerospace\",\"defense\",\"machining\"]`. Case-insensitive **substring** test against the lead's `CompanyName`, `Source`, and `Email`, plus — when the lead is linked to an Account — the account's `Industry`, `State`, `SizeBracket`, and `Name`. Any one needle found inside any one of those = hit.\n- **`{ \"industries\": [...] }`** — case-insensitive **exact** match against the linked account's `Industry` only (no substring; no account = no hit).\n- **`{ \"states\": [...] }`** — exact match against the linked account's `State`.\n- **`{ \"min\": N, \"max\": M }`** — inclusive numeric range against the account's `SizeBracket`, which **must parse as an integer** (`int.TryParse`). A non-numeric bracket never matches this shape.\n\n**Combining keys.** A single object MatchSpec may carry several of `industries` / `states` / `min`+`max` at once; they are evaluated **OR**-wise — the dimension hits as soon as the first key matches. To AND criteria, split them into separate dimensions. Note the object form depends entirely on the linked **Account** — a lead with no account can only ever match via the string-array shape.\n\n## Nightly scoring jobs explained\n\nTwo staggered Hangfire recurring jobs do all the scoring; nothing computes on demand.\n\n- **`compute-lead-icp-scores`** — Hangfire recurring-job id, runs `Cron.Daily(2, 15)` = **02:15 UTC** daily. Loads the one rubric that is `IsActive && IsDefault`, sums positive dimension weights as the denominator, then for every lead whose `Status` is **not** `Converted` and **not** `Lost`, sums matching-dimension weights and writes `Lead.IcpScore = clamp(round(hitWeight / maxScore * 100), 0, 100)`. Leads are processed in batches of 500 (`AsNoTracking` id pull, then a tracked batch load with `Include(Account)`) so a 50k-lead install doesn't exhaust memory. **Skip conditions** (logged, no scores written): no Active+Default rubric, default rubric has zero dimensions, or the sum of positive weights is 0.\n- **`recompute-lead-source-quality`** — runs `Cron.Daily(2, 30)` = **02:30 UTC** daily. For each **active** source it scores only leads created in the last **180 days**: `50 + 5×Converted + 2×Engaged − 5×(BadData + Suppressed) − 2×Lost`, clamped to 0–100, and stamps `LastScoredAt`. The 180-day window is what makes the score *rolling*; a fresh source with no in-window leads stays at the neutral 50. Inactive sources are skipped entirely. (`mark-stale-samples` follows at 02:45 — the three are staggered to avoid hammering the DB on the same minute.)\n\nBecause both jobs are nightly, every score you see in the UI is the cached result of the last run. Edits take effect on the next run, not immediately. A backlog accumulating faster than the job clears it shows up as a stale `LastScoredAt`.\n\n## Role / capability gating matrix\n\nThe three admin surfaces gate differently — completeness is deliberately the loosest.\n\n- **`/admin/lead-sources`** (`LeadSourcesController`) — capability **`CAP-O2C-LEAD`**. Read: `Admin, Manager, PM`. Create / Update: `Admin, Manager`. Delete: `Admin` only (and the delete is server-blocked when leads are linked).\n- **`/admin/icp-rubrics`** (`IcpRubricsController`) — capability **`CAP-O2C-LEAD`**. Read / Create / Update (including the bulk `POST /{id}/dimensions` save): `Admin, Manager`. Delete: `Admin` only.\n- **`/admin/entity-completeness`** authoring (`EntityCapabilityRequirementsController`, route `/api/v1/admin/entity-capability-requirements`) — **`Admin` only**, and **not** capability-gated (no `[RequiresCapability]`). Reads are admin-only too, since no operational page reads the raw rows.\n- **Completeness read endpoint** (`EntityCompletenessController`, `/api/v1/entities/{entityType}/{entityId}/completeness`) — any authenticated user; **not** capability-gated. The chip reports the status of *other* capabilities, so gating it would create a chicken-and-egg lockout. It does filter out requirements whose capability is currently **disabled**, so those never raise a false \"incomplete\".\n\n## Seed vs admin-authored completeness rows + i18n keys\n\n- **`IsSeedData` flag.** Each requirement row carries a boolean `IsSeedData`. Per Dan's option-B decision the catalog **ships empty** — there are no seeded rows today — so every row in a live install is admin-authored. The flag exists so a future seeded ruleset can be distinguished, and the admin UI may lock seeded rows from edit/delete.\n- **Composite uniqueness** is `(EntityType, CapabilityCode, RequirementId)` — that triple is what lets one capability declare several discrete checks (e.g. `CAP-P2P-PO` on Vendor needs both a `tax-id` row and a `payment-terms` row) so each surfaces as its own line in the missing-fields list.\n- **Ordering.** The evaluator returns missing fields ordered by `CapabilityCode`, then `SortOrder`, then `RequirementId`, grouped one section per capability.\n- **i18n keys are keys, not text.** `DisplayNameKey` (short chip label) and `MissingMessageKey` (fuller popover/error text) must have matching entries in `en.json` and `es.json` (100% parity is enforced by `lint:i18n`). A missing entry renders the **raw key token** in the chip — that is the tell-tale sign the wiring is incomplete. Convention: `entityCompleteness.fields.*` for labels, `entityCompleteness.messages.*` for explanations. There is no nightly job here — a predicate or key edit takes effect on the next completeness evaluation (the next time the chip loads).","sections":[]}"""
        });

        Log.Information("Seeded Lead Scoring training modules");
    }
